import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API = "http://localhost:3000/api";

function App() {
  const [user, setUser] = useState(null);
  const [view, setView] = useState("dashboard");
  const [students, setStudents] = useState([]);
  const [form, setForm] = useState({ id: "", pass: "" });

  useEffect(() => {
    if (user?.role === 'admin') loadStudents();
  }, [user]);

  const loadStudents = () => axios.get(`${API}/students`).then(res => setStudents(res.data));

  const handleLogin = () => {
    axios.post(`${API}/login`, { id: form.id, password: form.pass })
      .then(res => setUser(res.data))
      .catch(err => alert(err.response?.data?.message || "Khalad baa jira!"));
  };

  const updateStudent = (sid, newData) => {
    axios.put(`${API}/update/${encodeURIComponent(sid)}`, newData).then(loadStudents);
  };

  if (!user) {
    return (
      <div style={st.loginContainer}>
        <div style={st.card}>
          <h2 style={{color: '#1a73e8'}}>UOB PORTAL 2026</h2>
          <input placeholder="Username (admin / ID)" style={st.input} onChange={e => setForm({...form, id: e.target.value})} />
          <input type="password" placeholder="Password" style={st.input} onChange={e => setForm({...form, pass: e.target.value})} />
          <button onClick={handleLogin} style={st.loginBtn}>LOGIN</button>
        </div>
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', height: '100vh', background: '#f8f9fa' }}>
      {/* SIDEBAR */}
      <div style={st.sidebar}>
        <h2 style={{fontSize: '18px', marginBottom: '30px'}}>UOB SYSTEM</h2>
        <button onClick={() => setView("dashboard")} style={st.mBtn}>📊 Dashboard</button>
        {user.role === 'admin' && (
          <>
            <button onClick={() => setView("exam")} style={st.mBtn}>📝 Imtixaannada</button>
            <button onClick={() => setView("attendance")} style={st.mBtn}>📅 Xadiriska</button>
            <button onClick={() => setView("fees")} style={st.mBtn}>💰 Lacagaha</button>
          </>
        )}
        <button onClick={() => setUser(null)} style={st.outBtn}>Ka bax</button>
      </div>

      {/* CONTENT */}
      <div style={{ flex: 1, padding: '30px', overflowY: 'auto' }}>
        {user.role === 'admin' ? (
          <div>
            <h3>MAAMULKA: {view.toUpperCase()}</h3>
            <table style={st.table}>
              <thead>
                <tr style={{background: '#1a73e8', color: 'white'}}>
                  <th>ID</th><th>Magaca</th>
                  {view === "exam" && <th>B1 | Mid | B3 | Final</th>}
                  {view === "attendance" && <th>Xadiris (√ / X)</th>}
                  {view === "fees" && <th>Lacagta</th>}
                </tr>
              </thead>
              <tbody>
                {students.slice(0, 20).map(s => (
                  <tr key={s.id} style={{textAlign: 'center', borderBottom: '1px solid #ddd'}}>
                    <td style={{padding: '10px'}}>{s.id}</td><td>{s.magaca}</td>
                    <td>
                      {view === "exam" && (
                        <div style={{display: 'flex', gap: '3px', justifyContent: 'center'}}>
                          {['bil1', 'midterm', 'bil3', 'final'].map(k => (
                            <input key={k} type="number" style={st.mini} defaultValue={s.imtixaan[k]}
                              onBlur={e => updateStudent(s.id, { imtixaan: { ...s.imtixaan, [k]: e.target.value } })} />
                          ))}
                        </div>
                      )}
                      {view === "attendance" && (
                        <>
                          <button onClick={() => updateStudent(s.id, { attendance: { ...s.attendance, joogay: s.attendance.joogay + 1 } })} style={st.btnG}>√</button>
                          <button onClick={() => updateStudent(s.id, { attendance: { ...s.attendance, maqnaa: s.attendance.maqnaa + 1 } })} style={st.btnR}>X</button>
                        </>
                      )}
                      {view === "fees" && (
                        <select defaultValue={s.lacagta} onChange={e => updateStudent(s.id, { lacagta: e.target.value })}>
                          <option value="Ma bixin">Ma bixin</option><option value="Bixiyey">Bixiyey</option>
                        </select>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div style={{textAlign: 'center'}}>
            <div style={st.studentCard}>
              <h2>Warbixinta: {user.id}</h2>
              <div style={st.grid}>
                <div style={st.info}><h4>Bilaha 1</h4><p>{user.imtixaan?.bil1}%</p></div>
                <div style={st.info}><h4>Mid-Term</h4><p>{user.imtixaan?.midterm}%</p></div>
                <div style={st.info}><h4>Bilaha 3</h4><p>{user.imtixaan?.bil3}%</p></div>
                <div style={st.info}><h4>Final Exam</h4><p>{user.imtixaan?.final}%</p></div>
              </div>
              <div style={{marginTop: '20px'}}>
                 <p>Lacagta: <b>{user.lacagta}</b></p>
                 <p>Xadiriska: <b>{Math.round((user.attendance?.joogay / (user.attendance?.joogay + user.attendance?.maqnaa || 1)) * 100)}%</b></p>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

